            bounds := nativeHistogramBounds[schema]
            key = sort.SearchFloat64s(bounds, frac) + (exp-1)*len(bounds)
        } else {
            // Low-resolution (schema <= 0): power-of-two grouping
            key = exp
            if frac == 0.5 { key-- }
            offset := (1 << -schema) - 1
            key = (key + offset) >> -schema
